interfaces.definition:
interface InviteListResponse {
  count: number                                 // Общее количество инвайтов
  next: string | null                           // URL следующей страницы (если есть)
  previous: string | null                       // URL предыдущей страницы (если есть)
  results: Invite[]                             // Массив инвайтов текущей страницы
}

interface InvitesStatsProps {
  total: number                                 // Общее количество инвайтов
  pending: number                               // Количество инвайтов со статусом "pending"
  sent: number                                  // Количество инвайтов со статусом "sent"
  completed: number                             // Количество инвайтов со статусом "completed"
}

interface CreateInviteModalProps {
  isOpen: boolean                               // Флаг открытости модального окна
  onClose: () => void                           // Обработчик закрытия модального окна
  onSave?: (data: { combined_data: string }) => void // Обработчик успешного сохранения (опционально)
}
